import express from 'express';
import { randomUUID } from 'node:crypto';
import { sendError } from './lib/errors';
import projectsRouter from './modules/projects/routes';
import membersRouter from './modules/members/routes';
import tasksRouter from './modules/tasks/routes';
import commentsRouter from './modules/comments/routes';

const app = express();
app.use(express.json());

// Health endpoint
app.get('/health', (req, res) => {
  res.json({ ok: true });
});

// Routes
app.use('/projects', projectsRouter);
app.use('/projects/:projectId/members', membersRouter);
app.use('/projects/:projectId/tasks', tasksRouter);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRouter);

// Error handling middleware
app.use((err, req, res, next) => {
  if (err) {
    sendError(res, err.status || 500, err.code || 'INTERNAL_ERROR', err.message || 'Internal Server Error');
  } else {
    next();
  }
});

export default app;

import express from 'express';
import { getProjects, createProject } from './service';

const router = express.Router();

// List projects
router.get('/', async (req, res) => {
  const projects = await getProjects();
  res.json({ projects });
});

// Create project
router.post('/', async (req, res) => {
  if (!req.body.name) return sendError(res, 400, 'BAD_REQUEST', 'Name is required');
  const project = await createProject({ name: req.body.name });
  res.status(201).json({ project });
});

export default router;

import { sendError } from '../../lib/errors';
import prisma from '../../../prisma/client';

export const getProjects = async () => {
  return await prisma.project.findMany();
};

export const createProject = async ({ name }) => {
  if (!name) return null;
  return await prisma.project.create({ data: { name } });
};

import express from 'express';
import { getMembers, createMember } from './service';

const router = express.Router();

// List members
router.get('/', async (req, res) => {
  const projectId = req.params.projectId;
  if (!projectId) return sendError(res, 400, 'BAD_REQUEST', 'Project ID is required');
  const members = await getMembers(projectId);
  res.json({ members });
});

// Create member
router.post('/', async (req, res) => {
  if (!req.body.userId || !req.body.role) return sendError(res, 400, 'BAD_REQUEST', 'UserId and role are required');
  const member = await createMember({ projectId: req.params.projectId, userId: req.body.userId, role: req.body.role });
  res.status(201).json({ member });
});

export default router;

import { sendError } from '../../lib/errors';
import prisma from '../../../prisma/client';

export const getMembers = async (projectId) => {
  if (!projectId) return null;
  return await prisma.member.findMany({ where: { projectId } });
};

export const createMember = async ({ projectId, userId, role }) => {
  if (!userId || !role) return null;
  return await prisma.member.create({ data: { projectId, userId, role } });
};

import express from 'express';
import { getTasks, createTask, updateTaskStatus } from './service';

const router = express.Router();

// List tasks
router.get('/', async (req, res) => {
  const status = req.query.status;
  if (status && !['todo', 'done'].includes(status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid status');
  const tasks = await getTasks(req.params.projectId, status);
  res.json({ tasks });
});

// Update task status
router.patch('/:taskId/status', async (req, res) => {
  if (!['todo', 'done'].includes(req.body.status)) return sendError(res, 400, 'BAD_REQUEST', 'Invalid status');
  const task = await updateTaskStatus(req.params.taskId, req.body.status);
  res.json({ task });
});

export default router;

import { sendError } from '../../lib/errors';
import prisma from '../../../prisma/client';

export const getTasks = async (projectId, status) => {
  if (!projectId) return null;
  const where = status ? { projectId, status } : { projectId };
  return await prisma.task.findMany({ where });
};

export const createTask = async (projectId) => {
  if (!projectId) return null;
  return await prisma.task.create({ data: { projectId, status: 'todo' } });
};

export const updateTaskStatus = async (taskId, status) => {
  if (!['todo', 'done'].includes(status)) return null;
  return await prisma.task.update({ where: { id: taskId }, data: { status } });
};

import express from 'express';
import { getComments, createComment } from './service';

const router = express.Router();

// List comments
router.get('/', async (req, res) => {
  const taskId = req.params.taskId;
  if (!taskId) return sendError(res, 400, 'BAD_REQUEST', 'Task ID is required');
  const comments = await getComments(taskId);
  res.json({ comments });
});

// Create comment
router.post('/', async (req, res) => {
  if (!req.body.message) return sendError(res, 400, 'BAD_REQUEST', 'Message is required');
  const comment = await createComment({ taskId: req.params.taskId, message: req.body.message });
  res.status(201).json({ comment });
});

export default router;

import { sendError } from '../../lib/errors';
import prisma from '../../../prisma/client';

export const getComments = async (taskId) => {
  if (!taskId) return null;
  return await prisma.comment.findMany({ where: { taskId } });
};

export const createComment = async ({ taskId, message }) => {
  if (!message) return null;
  return await prisma.comment.create({ data: { taskId, message } });
};

const app = require('./app');
const port = process.env.PORT || 3000;

module.exports = app;

class BadRequestError extends Error {
  constructor(message) {
    super(message);
    this.code = 'E_BADREQUEST';
  }
}
exports.sendError = function(res, status, code, message) {
  res.status(status).json({ error: { code, message } });
};

const { randomUUID } = require('node:crypto');
exports.generateId = function() {
  return randomUUID();
};
